/** @since 5.0 */
export interface LayerViewHighlightOptions {
  /**
   * The [HighlightOptions.name](https://developers.arcgis.com/javascript/latest/references/core/views/support/HighlightOptions/#name) of the highlight options from the view's [View.highlights](https://developers.arcgis.com/javascript/latest/references/core/views/View/#highlights) collection.
   * If a `name` is provided, the corresponding highlight options will be applied to the feature(s). Otherwise, the `default` highlight options will be used.
   *
   * @since 5.0
   */
  readonly name?: string;
}